package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Locator;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP20CrearPedidoMultiplesProductosPlaywrightTest extends BaseTestPlaywright {    @Test    void crearPedidoConMultiplesProductos() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("camarero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForLoadState();        page.locator("a:has-text('Crear pedido'), a:has-text('Crear Pedido')")                .first()                .click();        page.waitForLoadState();        Locator selectorProductos = page.locator("select").first();        assertTrue(                selectorProductos.count() > 0,                "No se encontró el selector de productos."        );        String valueProductoUno = selectorProductos.locator("option").nth(1).getAttribute("value");        String nombreProductoUno = selectorProductos.locator("option").nth(1).textContent();        selectorProductos.selectOption(valueProductoUno);        page.locator("input[type='number']").first().fill("2");        page.locator("button:has-text('Agregar')")                .first()                .click();        page.waitForTimeout(1000);        selectorProductos = page.locator("select").first();        String valueProductoDos = selectorProductos.locator("option").nth(2).getAttribute("value");        String nombreProductoDos = selectorProductos.locator("option").nth(2).textContent();        selectorProductos.selectOption(valueProductoDos);        page.locator("input[type='number']").first().fill("1");        page.locator("button:has-text('Agregar')")                .first()                .click();        page.waitForTimeout(1000);        String contenidoAntesGuardar = page.content();        assertTrue(                contenidoAntesGuardar.contains("Total")                        || contenidoAntesGuardar.contains("S/."),                "No se visualiza el total del pedido antes de guardarlo."        );        page.locator("button:has-text('Guardar Pedido')")                .first()                .click();        page.waitForLoadState();        page.waitForTimeout(1500);        String contenidoFinal = page.content();        assertTrue(                contenidoFinal.contains("Pedidos Actuales")                        || contenidoFinal.contains("Pendiente")                        || contenidoFinal.contains(nombreProductoUno.trim())                        || contenidoFinal.contains(nombreProductoDos.trim()),                "El pedido con múltiples productos no aparece registrado."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get("evidencias/HP20-crear-pedido-multiples-productos.png"))                        .setFullPage(true)        );    }}